import { useState } from "react";
import { getPatients, getAppointments, getPrescriptions } from "../api";
import jsPDF from "jspdf";

export default function Search() {
  const [phone, setPhone] = useState("");
  const [patients, setPatients] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [patient, setPatient] = useState(null);
  const [prescriptions, setPrescriptions] = useState([]);

  // ================= SEARCH =================
  const handleSearch = async () => {
    const allPatients = await getPatients();

    const found = allPatients.find((p) => p.phone === phone);

    if (!found) {
      alert("Patient not found");
      setPatient(null);
      setAppointments([]);
      setPrescriptions([]);
      return;
    }

    setPatient(found);

    // Get appointments
    const apps = await getAppointments();
    setAppointments(apps.filter((a) => a.patient_id === found.id));

    // Get prescriptions
    const pres = await getPrescriptions(found.id);
    setPrescriptions(pres);
  };

  // ================= PRINT =================
  const handlePrint = () => {
    window.print();
  };

  // ================= PDF =================
  const handleDownloadPDF = (p) => {
    const doc = new jsPDF();

    doc.setFontSize(18);
    doc.text("Dental Prescription", 20, 20);

    doc.setFontSize(12);
    doc.text(`Patient: ${patient.name}`, 20, 40);
    doc.text(`Phone: ${patient.phone}`, 20, 50);

    doc.text("Medicines:", 20, 70);
    doc.text(p.medicines || "", 20, 80);

    doc.text("Notes:", 20, 100);
    doc.text(p.notes || "", 20, 110);

    doc.text(`Date: ${new Date(p.date).toLocaleString()}`, 20, 130);

    doc.text("Doctor Signature: ____________", 20, 160);

    doc.save(`prescription_${p.id}.pdf`);
  };

  // ================= UI =================
  return (
    <div style={{ padding: "20px" }}>
      <h2>🔎 Search Patient</h2>

      <input
        placeholder="Enter phone number"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
      />

      <br /><br />

      <button onClick={handleSearch}>Search</button>
      <button onClick={handlePrint} style={{ marginLeft: "10px" }}>
        Print
      </button>

      {/* ================= RESULT ================= */}
      {patient && (
        <div
          style={{
            marginTop: "20px",
            background: "#fff",
            padding: "20px",
            borderRadius: "10px",
          }}
        >
          <h2>Patient Profile</h2>
          <p><b>Name:</b> {patient.name}</p>
          <p><b>Phone:</b> {patient.phone}</p>
          <p><b>Age:</b> {patient.age}</p>

          {/* APPOINTMENTS */}
          <h3 style={{ marginTop: "20px" }}>Appointments</h3>
          {appointments.length === 0 ? (
            <p>No appointments</p>
          ) : (
            appointments.map((a) => (
              <div key={a.id}>
                {new Date(a.date).toLocaleString()}
              </div>
            ))
          )}

          {/* PRESCRIPTIONS */}
          <h3 style={{ marginTop: "20px" }}>Prescriptions</h3>
          {prescriptions.length === 0 ? (
            <p>No prescriptions</p>
          ) : (
            prescriptions.map((p) => (
              <div
                key={p.id}
                style={{
                  background: "#f9f9f9",
                  padding: "10px",
                  marginBottom: "10px",
                  borderRadius: "8px",
                }}
              >
                <p><b>Medicines:</b> {p.medicines}</p>
                <p><b>Notes:</b> {p.notes}</p>
                <p><b>Date:</b> {new Date(p.date).toLocaleString()}</p>

                <button onClick={() => handleDownloadPDF(p)}>
                  Download PDF
                </button>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
